def process_graph(graph_data):

    graph_copy = graph_data.copy()
    node_to_remove = 'ju1.a3.m1.s2c7'

    if node_to_remove in graph_copy:
        graph_copy.remove_node(node_to_remove)

    # Find the parent node ju1.a3.m1
    parent_node = None
    for node in graph_copy.nodes(data=True):
        if node[1]['name'] == 'ju1.a3.m1':
            parent_node = node[0]
            break

    child_capacity_list = []

    if parent_node:
        # Get all direct children via RK_CONTAINS edges
        for edge in graph_copy.edges(data=True):
            if edge[0] == parent_node and edge[2]['type'] == 'RK_CONTAINS':
                child_node = edge[1]
                child_attrs = graph_copy.nodes[child_node]
                total_capacity = 0

                # Traverse all descendants to sum PORT physical_capacity_bps
                successors = nx.descendants(graph_copy, child_node)
                for succ in successors:
                    succ_attrs = graph_copy.nodes[succ]
                    if 'EK_PORT' in succ_attrs['type'] and 'physical_capacity_bps' in succ_attrs:
                        total_capacity += succ_attrs['physical_capacity_bps']

                # Also check if the child itself is a PORT
                if 'EK_PORT' in child_attrs['type'] and 'physical_capacity_bps' in child_attrs:
                    total_capacity += child_attrs['physical_capacity_bps']

                child_capacity_list.append((child_attrs['name'], total_capacity))

        # Sort by physical capacity descending
        child_capacity_list.sort(key=lambda x: x[1], reverse=True)

    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)

    return_object = {
        'type': 'list',
        'data': child_capacity_list,
        'updated_graph': graph_json
    }

    return return_object

